let catalogVersion = 1;
let lastSyncedAt = new Date('2026-07-15T09:00:00.000Z');

function buildCatalog(version) {
  const inventoryOffset = (version - 1) * 3;
  const priceOffset = (version - 1) * 10;

  return [
    {
      id: 'sku-1001',
      name: 'Laptop',
      price: 999 + priceOffset,
      inventory: 12 + inventoryOffset,
      availability: version % 2 === 0 ? 'Backorder' : 'In stock',
    },
    {
      id: 'sku-1002',
      name: 'Phone',
      price: 699 + priceOffset,
      inventory: 30 + inventoryOffset,
      availability: 'In stock',
    },
    {
      id: 'sku-1003',
      name: 'Tablet',
      price: 499 + priceOffset,
      inventory: 18 + inventoryOffset,
      availability: version % 3 === 0 ? 'Low stock' : 'In stock',
    },
    {
      id: 'sku-1004',
      name: 'Headphones',
      price: 199 + priceOffset,
      inventory: 45 + inventoryOffset,
      availability: 'In stock',
    },
    {
      id: 'sku-1005',
      name: 'Watch',
      price: 299 + priceOffset,
      inventory: 9 + inventoryOffset,
      availability: version % 2 === 0 ? 'Low stock' : 'In stock',
    },
  ];
}

export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));

  return {
    products: buildCatalog(catalogVersion),
    meta: {
      version: catalogVersion,
      lastSyncedAt: lastSyncedAt.toISOString(),
    },
  };
}

export async function syncLatestCatalog() {
  await new Promise((resolve) => setTimeout(resolve, 1000));

  catalogVersion += 1;
  lastSyncedAt = new Date();

  return {
    version: catalogVersion,
    lastSyncedAt: lastSyncedAt.toISOString(),
    updatedSkuCount: 2847,
  };
}

import { cacheTag, revalidateTag } from 'next/cache';
import { getAllProducts, syncLatestCatalog } from '@/lib/db';

async function getCachedCatalog() {
  'use cache';
  cacheTag('products');

  return getAllProducts();
}

function currency(value: number) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD'
  }).format(value);
}

export default async function Page() {
  const { products, meta } = await getCachedCatalog();

  async function syncCatalogAction() {
    'use server';

    void (async () => {
      await syncLatestCatalog();
      revalidateTag('products', 'max');
    })();
  }

  return (
    <main style={{ fontFamily: 'Arial, sans-serif', padding: 32 }}>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          gap: 24,
          marginBottom: 24
        }}
      >
        <div>
          <h1 style={{ margin: 0, fontSize: 32 }}>Admin product catalog</h1>
          <p style={{ margin: '8px 0 0', color: '#555', maxWidth: 700 }}>
            Browse the current catalog snapshot quickly. When ERP or PIM updates land,
            trigger a background sync and continue working while cached product data is
            refreshed shortly after across catalog views.
          </p>
        </div>

        <form action={syncCatalogAction}>
          <button
            type="submit"
            style={{
              border: 'none',
              borderRadius: 8,
              background: '#111827',
              color: '#fff',
              padding: '12px 16px',
              fontWeight: 600,
              cursor: 'pointer'
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      <section
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(3, minmax(0, 1fr))',
          gap: 16,
          marginBottom: 24
        }}
      >
        <div style={{ padding: 16, border: '1px solid #e5e7eb', borderRadius: 12 }}>
          <div style={{ color: '#6b7280', fontSize: 14 }}>Cached catalog version</div>
          <div style={{ fontSize: 28, fontWeight: 700 }}>{meta.version}</div>
        </div>
        <div style={{ padding: 16, border: '1px solid #e5e7eb', borderRadius: 12 }}>
          <div style={{ color: '#6b7280', fontSize: 14 }}>Last sync reflected in UI</div>
          <div style={{ fontSize: 18, fontWeight: 600 }}>
            {new Date(meta.lastSyncedAt).toLocaleString()}
          </div>
        </div>
        <div style={{ padding: 16, border: '1px solid #e5e7eb', borderRadius: 12 } }>
          <div style={{ color: '#6b7280', fontSize: 14 }}>Cache tag</div>
          <div style={{ fontSize: 18, fontWeight: 600 }}>products</div>
        </div>
      </section>

      <div style={{ overflowX: 'auto' }}>
        <table
          style={{
            width: '100%',
            borderCollapse: 'collapse',
            border: '1px solid #e5e7eb',
            borderRadius: 12,
            overflow: 'hidden'
          }}
        >
          <thead style={{ background: '#f9fafb' }}>
            <tr>
              <th style={{ textAlign: 'left', padding: 12, borderBottom: '1px solid #e5e7eb' }}>
                SKU
              </th>
              <th style={{ textAlign: 'left', padding: 12, borderBottom: '1px solid #e5e7eb' }}>
                Product
              </th>
              <th style={{ textAlign: 'left', padding: 12, borderBottom: '1px solid #e5e7eb' }}>
                Price
              </th>
              <th style={{ textAlign: 'left', padding: 12, borderBottom: '1px solid #e5e7eb' }}>
                Inventory
              </th>
              <th style={{ textAlign: 'left', padding: 12, borderBottom: '1px solid #e5e7eb' }}>
                Availability
              </th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id}>
                <td style={{ padding: 12, borderBottom: '1px solid #e5e7eb' }}>{product.id}</td>
                <td style={{ padding: 12, borderBottom: '1px solid #e5e7eb' }}>{product.name}</td>
                <td style={{ padding: 12, borderBottom: '1px solid #e5e7eb' }}>
                  {currency(product.price)}
                </td>
                <td style={{ padding: 12, borderBottom: '1px solid #e5e7eb' }}>
                  {product.inventory}
                </td>
                <td style={{ padding: 12, borderBottom: '1px solid #e5e7eb' }}>
                  {product.availability}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}

import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  cacheComponents: true
};

export default nextConfig;
